import fs from "node:fs";

const TRACE_REGISTRY_PATH = ".GOV/roles_shared/WP_TRACEABILITY_REGISTRY.md";
const TASK_BOARD_PATH = ".GOV/roles_shared/TASK_BOARD.md";
const TASK_PACKETS_DIR = ".GOV/task_packets";
const TASK_PACKET_STUBS_DIR = ".GOV/task_packets/stubs";

function fail(message, details = []) {
  console.error(`[PACKET_TRUTH_CHECK] ${message}`);
  for (const line of details) console.error(`  - ${line}`);
  process.exit(1);
}

function normalizePath(value) {
  return String(value || "").replace(/\\/g, "/").trim();
}

function packetIdFromPath(packetPath) {
  const normalized = normalizePath(packetPath);
  const last = normalized.split("/").filter(Boolean).pop() || "";
  return last.endsWith(".md") ? last.slice(0, -3) : last;
}

function parseSingleField(text, label) {
  const re = new RegExp(`^\\s*-\\s*(?:\\*\\*)?${label}(?:\\*\\*)?\\s*:\\s*(.+)\\s*$`, "mi");
  const match = text.match(re);
  return match ? match[1].trim() : "";
}

function parseStatus(text) {
  return (
    (text.match(/^\s*-\s*\*\*Status:\*\*\s*(.+)\s*$/mi) || [])[1] ||
    (text.match(/^\s*\*\*Status:\*\*\s*(.+)\s*$/mi) || [])[1] ||
    (text.match(/^\s*-\s*STUB_STATUS\s*:\s*(.+)\s*$/mi) || [])[1] ||
    (text.match(/^\s*-\s*STATUS\s*:\s*(.+)\s*$/mi) || [])[1] ||
    (text.match(/^\s*STATUS\s*:\s*(.+)\s*$/mi) || [])[1] ||
    ""
  ).trim();
}

function baseWpIdFromPacket(packetId, packetText) {
  const raw = parseSingleField(packetText, "BASE_WP_ID")
    .replace(/\s*\(.*/, "")
    .trim();
  if (raw) return raw;
  return packetId.replace(/-v\d+$/, "").replace(/-\d{8}$/, "");
}

function parseRegistryRows(content) {
  const rows = new Map();
  const lines = content.split(/\r?\n/);
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    if (!line.trim().startsWith("|")) continue;
    const parts = line.split("|").slice(1, -1).map((p) => p.trim());
    if (parts.length < 2) continue;
    const baseWpId = parts[0];
    const activePacketPath = normalizePath(parts[1]);
    if (!baseWpId.startsWith("WP-")) continue;
    rows.set(baseWpId, {
      baseWpId,
      activePacketPath,
      activePacketId: packetIdFromPath(activePacketPath),
      lineNumber: index + 1,
    });
  }
  return rows;
}

function parseTaskBoardTokens(content) {
  const tokens = new Map();
  const lines = content.split(/\r?\n/);
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index].trim();
    const match = line.match(/^- \*\*\[(WP-[^\]]+)\]\*\* - \[([^\]]+)\](?:\s*-\s*.+)?$/);
    if (!match) continue;
    tokens.set(match[1], { token: match[2], lineNumber: index + 1 });
  }
  return tokens;
}

function normalizedStatusKind(status) {
  const value = String(status || "").trim().toUpperCase();
  if (!value) return "UNKNOWN";
  if (value.includes("STUB")) return "STUB";
  if (value.includes("READY FOR DEV")) return "READY_FOR_DEV";
  if (value.includes("IN PROGRESS")) return "IN_PROGRESS";
  if (value.includes("BLOCKED")) return "BLOCKED";
  if (/VALIDATED\s*\(\s*PASS\s*\)/.test(value)) return "VALIDATED_PASS";
  if (/VALIDATED\s*\(\s*FAIL\s*\)/.test(value)) return "VALIDATED_FAIL";
  if (/VALIDATED\s*\(\s*OUTDATED_ONLY\s*\)/.test(value)) return "VALIDATED_OUTDATED_ONLY";
  if (value.includes("DONE") || value.includes("COMPLETE") || value.includes("VALIDATED")) return "DONE";
  return "UNKNOWN";
}

function expectedBoardTokens(statusKind, isStub) {
  if (isStub) return new Set(["STUB"]);
  if (statusKind === "READY_FOR_DEV") return new Set(["READY_FOR_DEV"]);
  if (statusKind === "IN_PROGRESS") return new Set(["IN_PROGRESS"]);
  if (statusKind === "BLOCKED") return new Set(["BLOCKED"]);
  if (statusKind === "VALIDATED_PASS") return new Set(["VALIDATED"]);
  if (statusKind === "VALIDATED_FAIL") return new Set(["FAIL"]);
  if (statusKind === "VALIDATED_OUTDATED_ONLY") return new Set(["OUTDATED_ONLY"]);
  if (statusKind === "DONE") return new Set(["VALIDATED", "FAIL", "OUTDATED_ONLY"]);
  return new Set();
}

function readPacketInventory(dir, kind) {
  const entries = [];
  if (!fs.existsSync(dir)) return entries;
  for (const name of fs.readdirSync(dir).filter((file) => file.endsWith(".md") && file !== "README.md")) {
    const filePath = `${dir}/${name}`.replace(/\\/g, "/");
    const packetId = name.slice(0, -3);
    const text = fs.readFileSync(filePath, "utf8");
    entries.push({
      kind,
      filePath,
      packetId,
      packetText: text,
      baseWpId: baseWpIdFromPacket(packetId, text),
      status: parseStatus(text),
    });
  }
  return entries;
}

const registryContent = fs.existsSync(TRACE_REGISTRY_PATH)
  ? fs.readFileSync(TRACE_REGISTRY_PATH, "utf8")
  : "";
const taskBoardContent = fs.existsSync(TASK_BOARD_PATH)
  ? fs.readFileSync(TASK_BOARD_PATH, "utf8")
  : "";

const registryRows = parseRegistryRows(registryContent);
const taskBoardTokens = parseTaskBoardTokens(taskBoardContent);

const officialPackets = readPacketInventory(TASK_PACKETS_DIR, "official");
const stubPackets = readPacketInventory(TASK_PACKET_STUBS_DIR, "stub");
const allPackets = [...officialPackets, ...stubPackets];

const packetsByBaseWpId = new Map();
for (const packet of allPackets) {
  const list = packetsByBaseWpId.get(packet.baseWpId) || [];
  list.push(packet);
  packetsByBaseWpId.set(packet.baseWpId, list);
}

const violations = [];

for (const [baseWpId, registryRow] of registryRows.entries()) {
  const activePacket = allPackets.find((packet) => packet.packetId === registryRow.activePacketId);
  if (!activePacket) {
    violations.push(
      `${TRACE_REGISTRY_PATH}:${registryRow.lineNumber}: Active packet missing on disk for ${baseWpId} (${registryRow.activePacketPath})`
    );
    continue;
  }

  if (activePacket.baseWpId !== baseWpId) {
    violations.push(
      `${TRACE_REGISTRY_PATH}:${registryRow.lineNumber}: Active packet ${activePacket.packetId} declares BASE_WP_ID=${activePacket.baseWpId}, expected ${baseWpId}`
    );
  }

  const boardEntry = taskBoardTokens.get(activePacket.packetId);
  if (!boardEntry) {
    violations.push(
      `${TASK_BOARD_PATH}: missing projection entry for active packet ${activePacket.packetId} (BASE_WP_ID=${baseWpId})`
    );
  } else {
    const expected = expectedBoardTokens(normalizedStatusKind(activePacket.status), activePacket.kind === "stub");
    if (expected.size === 0) {
      violations.push(
        `${activePacket.filePath}: cannot derive Task Board projection from packet status "${activePacket.status}" for active packet ${activePacket.packetId}`
      );
    } else if (!expected.has(boardEntry.token)) {
      violations.push(
        `${TASK_BOARD_PATH}:${boardEntry.lineNumber}: active packet ${activePacket.packetId} has status "${activePacket.status}" but Task Board token is [${boardEntry.token}]`
      );
    }
    if (boardEntry.token === "SUPERSEDED") {
      violations.push(
        `${TASK_BOARD_PATH}:${boardEntry.lineNumber}: active packet ${activePacket.packetId} cannot be marked [SUPERSEDED]`
      );
    }
  }

  const siblings = packetsByBaseWpId.get(baseWpId) || [];
  for (const sibling of siblings) {
    if (sibling.packetId === activePacket.packetId) continue;
    const olderBoardEntry = taskBoardTokens.get(sibling.packetId);
    if (!olderBoardEntry) {
      violations.push(
        `${TASK_BOARD_PATH}: older packet ${sibling.packetId} shares BASE_WP_ID=${baseWpId} with active packet ${activePacket.packetId} but is not marked [SUPERSEDED]`
      );
      continue;
    }
    if (olderBoardEntry.token !== "SUPERSEDED") {
      violations.push(
        `${TASK_BOARD_PATH}:${olderBoardEntry.lineNumber}: older packet ${sibling.packetId} shares BASE_WP_ID=${baseWpId} with active packet ${activePacket.packetId} and must be [SUPERSEDED], not [${olderBoardEntry.token}]`
      );
    }
  }
}

if (violations.length > 0) {
  fail("Packet truth drift detected", violations);
}

console.log("packet-truth-check ok");

#!/usr/bin/env node

import fs from "node:fs";
import {
  TOPOLOGY_REGISTRY_JSON_PATH,
  TOPOLOGY_REGISTRY_MD_PATH,
  absFromRepo,
  buildTopologyRegistry,
  renderTopologyRegistryMd,
} from "../git-topology-lib.mjs";

const expectedJson = `${JSON.stringify(buildTopologyRegistry(), null, 2)}\n`;
const expectedMd = renderTopologyRegistryMd(buildTopologyRegistry());
const jsonPath = absFromRepo(TOPOLOGY_REGISTRY_JSON_PATH);
const mdPath = absFromRepo(TOPOLOGY_REGISTRY_MD_PATH);

const errors = [];
if (!fs.existsSync(jsonPath)) {
  errors.push(`Missing ${TOPOLOGY_REGISTRY_JSON_PATH}`);
} else if (fs.readFileSync(jsonPath, "utf8") !== expectedJson) {
  errors.push(`${TOPOLOGY_REGISTRY_JSON_PATH} is stale; run just topology-registry-sync`);
}

if (!fs.existsSync(mdPath)) {
  errors.push(`Missing ${TOPOLOGY_REGISTRY_MD_PATH}`);
} else if (fs.readFileSync(mdPath, "utf8") !== expectedMd) {
  errors.push(`${TOPOLOGY_REGISTRY_MD_PATH} is stale; run just topology-registry-sync`);
}

if (errors.length > 0) {
  for (const error of errors) console.error(`FAIL: ${error}`);
  process.exit(1);
}

console.log("topology-registry-check ok");

#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";
import { execFileSync, spawnSync } from "node:child_process";
import { fileURLToPath } from "node:url";

export const SCHEMA_VERSION = "hsk.git_topology_registry@0.1";
export const DYNAMIC_SNAPSHOT_SCHEMA_VERSION = "hsk.git_topology_snapshot@0.1";
export const TOPOLOGY_REGISTRY_JSON_PATH = ".GOV/roles_shared/GIT_TOPOLOGY_REGISTRY.json";
export const TOPOLOGY_REGISTRY_MD_PATH = ".GOV/roles_shared/GIT_TOPOLOGY_REGISTRY.md";
export const PROTECTED_BRANCHES = ["main", "user_ilja", "role_orchestrator", "role_validator"];
export const WORKTREE_SPECS = [
  {
    id: "handshake_main",
    rel_path: "../handshake_main",
    local_branch: "main",
    remote_branch: "origin/main",
    role: "CANONICAL",
    canonical: true,
    description: "Canonical integrated checkout on disk",
  },
  {
    id: "wt-ilja",
    rel_path: "../wt-ilja",
    local_branch: "user_ilja",
    remote_branch: "origin/user_ilja",
    role: "OPERATOR",
    canonical: false,
    description: "Operator backup worktree",
  },
  {
    id: "wt-orchestrator",
    rel_path: "../wt-orchestrator",
    local_branch: "role_orchestrator",
    remote_branch: "origin/role_orchestrator",
    role: "ORCHESTRATOR",
    canonical: false,
    description: "Orchestrator backup worktree",
  },
  {
    id: "wt-validator",
    rel_path: "../wt-validator",
    local_branch: "role_validator",
    remote_branch: "origin/role_validator",
    role: "VALIDATOR",
    canonical: false,
    description: "Validator backup worktree",
  },
];

export const SNAPSHOT_EXCLUDE_DIRS = [
  ".git",
  "node_modules",
  ".next",
  ".turbo",
  "dist",
  "build",
  "target",
  ".pnpm-store",
];
export const SNAPSHOT_EXCLUDE_FILES = [".git"];

function resolveRepoRoot() {
  try {
    const out = execFileSync("git", ["rev-parse", "--show-toplevel"], {
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim();
    if (out) return out;
  } catch {
    // Ignore and fall back to file-relative resolution.
  }
  return path.resolve(path.dirname(fileURLToPath(import.meta.url)), "../..");
}

export const REPO_ROOT = path.resolve(resolveRepoRoot());
export const WORKSPACE_ROOT = path.resolve(REPO_ROOT, "..");

export const compareStrings = (a, b) => (a < b ? -1 : a > b ? 1 : 0);
export const toPosix = (value) => String(value || "").replace(/\\/g, "/");
export const absFromRepo = (relPath) => path.resolve(REPO_ROOT, relPath);
export const relFromRepo = (absPath) => toPosix(path.relative(REPO_ROOT, absPath));
export const absFromWorkspace = (relPath) => path.resolve(WORKSPACE_ROOT, relPath);
export const relFromWorkspace = (absPath) => toPosix(path.relative(WORKSPACE_ROOT, absPath));

export function runGit(args, options = {}) {
  return execFileSync("git", args, {
    encoding: "utf8",
    stdio: ["ignore", "pipe", "ignore"],
    ...options,
  }).trim();
}

export function runGitInRepo(repoDir, args, options = {}) {
  return execFileSync("git", args, {
    cwd: repoDir,
    encoding: "utf8",
    stdio: ["ignore", "pipe", "ignore"],
    ...options,
  }).trim();
}

export function runGitInherit(repoDir, args) {
  execFileSync("git", args, { cwd: repoDir, stdio: "inherit" });
}

export function localBranchExists(repoDir, branch) {
  try {
    execFileSync("git", ["show-ref", "--verify", "--quiet", `refs/heads/${branch}`], {
      cwd: repoDir,
      stdio: "ignore",
    });
    return true;
  } catch {
    return false;
  }
}

export function refExists(repoDir, refName) {
  try {
    execFileSync("git", ["rev-parse", "--verify", "--quiet", refName], {
      cwd: repoDir,
      stdio: "ignore",
    });
    return true;
  } catch {
    return false;
  }
}

export function gitCheckoutExists(absDir) {
  return fs.existsSync(path.join(absDir, ".git"));
}

export function currentBranchInRepo(repoDir) {
  return runGitInRepo(repoDir, ["branch", "--show-current"]);
}

export function headShaInRepo(repoDir) {
  return runGitInRepo(repoDir, ["rev-parse", "HEAD"]);
}

export function dirtyInRepo(repoDir) {
  return runGitInRepo(repoDir, ["status", "--porcelain=v1"]).length > 0;
}

export function listLocalBranches(repoDir) {
  const out = runGitInRepo(repoDir, ["for-each-ref", "--format=%(refname:short)", "refs/heads"]);
  return out.split(/\r?\n/).map((line) => line.trim()).filter(Boolean).sort(compareStrings);
}

export function listRemoteHeads(repoDir = REPO_ROOT) {
  const out = runGitInRepo(repoDir, ["ls-remote", "--heads", "origin"]);
  const rows = out.split(/\r?\n/).map((line) => line.trim()).filter(Boolean).map((line) => {
    const [sha, ref] = line.split(/\s+/);
    const branch = String(ref || "").replace("refs/heads/", "");
    return { branch, sha };
  });
  rows.sort((a, b) => compareStrings(a.branch, b.branch));
  return rows;
}

export function discoverGitCheckouts() {
  const entries = fs.readdirSync(WORKSPACE_ROOT, { withFileTypes: true })
    .filter((entry) => entry.isDirectory())
    .map((entry) => {
      const absDir = path.join(WORKSPACE_ROOT, entry.name);
      return {
        id: entry.name,
        abs_dir: absDir,
        rel_path: relFromRepo(absDir),
        is_git_checkout: gitCheckoutExists(absDir),
      };
    })
    .filter((entry) => entry.is_git_checkout)
    .sort((a, b) => compareStrings(a.id, b.id));
  return entries;
}

export function buildTopologyRegistry() {
  return {
    schema_version: SCHEMA_VERSION,
    canonical_branch: "main",
    protected_local_branches: [...PROTECTED_BRANCHES],
    protected_remote_branches: PROTECTED_BRANCHES.map((branch) => `origin/${branch}`),
    protected_worktrees: WORKTREE_SPECS.map((spec) => ({
      id: spec.id,
      rel_path: spec.rel_path,
      role: spec.role,
      canonical: spec.canonical,
      local_branch: spec.local_branch,
      remote_branch: spec.remote_branch,
      description: spec.description,
    })),
    helper_commands: {
      backup_snapshot: "just backup-snapshot",
      backup_status: "just backup-status",
      sync_all_role_worktrees: "just sync-all-role-worktrees",
      enumerate_cleanup_targets: "just enumerate-cleanup-targets",
      delete_local_worktree: "just delete-local-worktree",
      ensure_permanent_backup_branches: "just ensure-permanent-backup-branches",
    },
    backup_policy: {
      backup_push_before_destructive_local_git: true,
      immutable_snapshot_before_topology_deletion: true,
      nas_copy_mode: "timestamped_copy_no_mirror_deletes",
      backup_root_env_var: "HANDSHAKE_BACKUP_ROOT",
      nas_backup_root_env_var: "HANDSHAKE_NAS_BACKUP_ROOT",
    },
  };
}

export function renderTopologyRegistryMd(registry) {
  const lines = [
    "# GIT_TOPOLOGY_REGISTRY",
    "",
    "This file is a deterministic governance registry for the permanent Handshake checkout topology.",
    "",
    `- SCHEMA_VERSION: ${registry.schema_version}`,
    `- CANONICAL_BRANCH: ${registry.canonical_branch}`,
    `- PROTECTED_LOCAL_BRANCHES: ${registry.protected_local_branches.join(", ")}`,
    `- PROTECTED_REMOTE_BRANCHES: ${registry.protected_remote_branches.join(", ")}`,
    "",
    "## PROTECTED_WORKTREES",
    "",
    "| ID | ROLE | REL_PATH | LOCAL_BRANCH | REMOTE_BRANCH | CANONICAL | DESCRIPTION |",
    "| --- | --- | --- | --- | --- | --- | --- |",
  ];

  for (const row of registry.protected_worktrees) {
    lines.push(`| ${row.id} | ${row.role} | ${row.rel_path} | ${row.local_branch} | ${row.remote_branch} | ${row.canonical ? "YES" : "NO"} | ${row.description} |`);
  }

  lines.push(
    "",
    "## HELPER_COMMANDS",
    "",
    `- backup_snapshot: ${registry.helper_commands.backup_snapshot}`,
    `- backup_status: ${registry.helper_commands.backup_status}`,
    `- sync_all_role_worktrees: ${registry.helper_commands.sync_all_role_worktrees}`,
    `- enumerate_cleanup_targets: ${registry.helper_commands.enumerate_cleanup_targets}`,
    `- delete_local_worktree: ${registry.helper_commands.delete_local_worktree}`,
    `- ensure_permanent_backup_branches: ${registry.helper_commands.ensure_permanent_backup_branches}`,
    "",
    "## BACKUP_POLICY",
    "",
    `- BACKUP_PUSH_BEFORE_DESTRUCTIVE_LOCAL_GIT: ${registry.backup_policy.backup_push_before_destructive_local_git ? "YES" : "NO"}`,
    `- IMMUTABLE_SNAPSHOT_BEFORE_TOPOLOGY_DELETION: ${registry.backup_policy.immutable_snapshot_before_topology_deletion ? "YES" : "NO"}`,
    `- NAS_COPY_MODE: ${registry.backup_policy.nas_copy_mode}`,
    `- BACKUP_ROOT_ENV_VAR: ${registry.backup_policy.backup_root_env_var}`,
    `- NAS_BACKUP_ROOT_ENV_VAR: ${registry.backup_policy.nas_backup_root_env_var}`,
    "",
  );
  return `${lines.join("\n")}\n`;
}

export function buildDynamicTopologySnapshot() {
  const registry = buildTopologyRegistry();
  const protectedWorktrees = registry.protected_worktrees.map((spec) => {
